import{_ as d}from"./chunks/lekt4301.Br9NsjuL.js";import{_ as r,o as i,c as a,ag as l}from"./chunks/framework.DXGyWiRo.js";const e="/images/lekt4401.jpg",n="/images/lekt4402.jpg",o="/images/lekt4403.jpg",s="/images/lekt4404.jpg",h="/images/lekt4405.jpg",u="/images/lekt4406.jpg",b="/images/lekt4407.jpg",p="/images/lekt4408.jpg",m="/images/lekt4409.jpg",_=JSON.parse('{"title":"Lektion 44","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion44.md","filePath":"lektionen/lektion44.md"}'),c={name:"lektionen/lektion44.md"};function k(g,t,f,q,P,v){return i(),a("div",null,[...t[0]||(t[0]=[l('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-44" tabindex="-1">Lektion 44 <a class="header-anchor" href="#lektion-44" aria-label="Permalink to &quot;Lektion 44&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>44.1.  Bildung der Verbalformen der 2. Person (मध्यमः) athematischer Stämme mit vokalisch endendem Suffix <ul><li>44.1.1. Fünfte Präsensklasse (स्वादि)</li><li>44.1.2. Achte Präsensklasse (तनादि)</li><li>44.1.3. Neunte Präsensklasse (क्र्यादि)</li></ul></li><li>44.2. Zum Wortsandhi <ul><li>44.2.1. Zum Wortsandhi für dh-</li><li>44.2.2. Zum Wortsandhi für s-</li></ul></li><li>44.3.  Bildung der Verbalformen der 2. Person (मध्यमः) athematischer Stämme ohne vokalisch endendem Suffix <ul><li>44.3.1. Zweite Präsensklasse (अदादि)</li></ul></li><li>44.4. Der Vokativ (आमन्त्रितम्)</li><li>44.5. Wortliste</li><li>44.6. Übung</li><li>44.7. Wiederholungsübung zur Formenlehre</li></ul><h2 id="_44-1-bildung-der-verbalformen-der-2-person-मध्यमः-athematischer-stamme-mit-vokalisch-endendem-suffix" tabindex="-1">44.1.  Bildung der Verbalformen der 2. Person (मध्यमः) athematischer Stämme mit vokalisch endendem Suffix <a class="header-anchor" href="#_44-1-bildung-der-verbalformen-der-2-person-मध्यमः-athematischer-stamme-mit-vokalisch-endendem-suffix" aria-label="Permalink to &quot;44.1.  Bildung der Verbalformen der 2. Person (मध्यमः) athematischer Stämme mit vokalisch endendem Suffix&quot;">​</a></h2><p><img src="'+d+'" alt=""></p><p>Die 3.sg.Ā.Imperfekt ist formgleich mit der 2.pl.P.Imperfekt!!!</p><h3 id="_44-1-1-funfte-prasensklasse-स्वादि" tabindex="-1">44.1.1. Fünfte Präsensklasse (स्वादि) <a class="header-anchor" href="#_44-1-1-funfte-prasensklasse-स्वादि" aria-label="Permalink to &quot;44.1.1. Fünfte Präsensklasse (स्वादि)&quot;">​</a></h3><p>सु 5U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>सुनोषि</td><td></td></tr><tr><td>Cerebralisation!</td><td>सुनुथ</td><td>सुनुषे</td></tr><tr><td>Cerabralisation!</td><td>सुनुध्वे</td><td></td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>असुनोस्</td><td>असुनुत</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>सुनुयास्</td><td>सुनुयात</td></tr></tbody></table></blockquote><h3 id="_44-1-2-achte-prasensklasse-तनादि" tabindex="-1">44.1.2. Achte Präsensklasse (तनादि) <a class="header-anchor" href="#_44-1-2-achte-prasensklasse-तनादि" aria-label="Permalink to &quot;44.1.2. Achte Präsensklasse (तनादि)&quot;">​</a></h3><p>तन् 8U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>तनोषि</td><td>तनुथ</td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अतनोस्</td><td>अतनुत</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>तनुयास्</td><td>तनुयात</td></tr></tbody></table></blockquote><p>कृ 8U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>करोषि</td><td>कुरुथ</td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अकरोस्</td><td>अकुरुत</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>कुर्यास्</td><td>कुर्यात</td></tr></tbody></table></blockquote><h3 id="_44-1-3-neunte-prasensklasse-क्र्यादि" tabindex="-1">44.1.3. Neunte Präsensklasse (क्र्यादि) <a class="header-anchor" href="#_44-1-3-neunte-prasensklasse-क्र्यादि" aria-label="Permalink to &quot;44.1.3. Neunte Präsensklasse (क्र्यादि)&quot;">​</a></h3><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>क्रीणासि</td><td>क्रीणीथ</td></tr><tr><td>Cerebralisation!</td><td>क्रीणीध्वे</td><td></td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अक्रीणास्</td><td>अक्रीणीत</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>क्रीणीयास्</td><td>क्रीणीयात</td></tr><tr><td>krī + n + ī-thās</td><td>क्रीणीध्वम्</td><td></td></tr><tr><td>krī + n + ī-dhvam</td><td></td><td></td></tr></tbody></table></blockquote><h2 id="_44-2-zum-wortsandhi" tabindex="-1">44.2. Zum Wortsandhi <a class="header-anchor" href="#_44-2-zum-wortsandhi" aria-label="Permalink to &quot;44.2. Zum Wortsandhi&quot;">​</a></h2><p>Bei konsonantisch auslautenden Präsensstämmen sind die schon behandelten Gesetze des Wortsandhi zu beachten.</p><p>Außerdem kommen noch folgende Gesetze des Wortsandhi zur Anwendung.</p><p>(Ausführliche Zusammenstellung aller hierher gehörigen Lautveränserungen bei Kielhorn, Grammatik S. 76f.)</p><h3 id="_44-2-1-zum-wortsandhi-fur-dh" tabindex="-1">44.2.1. Zum Wortsandhi für dh- <a class="header-anchor" href="#_44-2-1-zum-wortsandhi-fur-dh" aria-label="Permalink to &quot;44.2.1. Zum Wortsandhi für dh-&quot;">​</a></h3><p>1. Aspirata wird vor Aspirata durch den entsprechenden Nichtspiraten ersetzt:</p><blockquote><p>z.B. रुध् 7U: रुन्ध् + ध्वे » रुन्द्ध्वे (runddhve)</p></blockquote><p>2. -h + dh- » -gdh-</p><blockquote><p>z.B. दुह् 2U: दुह् + ध्वे » धुग्ध्वे (dhugdhve)</p></blockquote><p>3. -ṣ + dh- » -ḍḍh- (Diese Regel gilt nur für die Konjugation!)</p><blockquote><p>z.B. द्विष् 2U: द्विष् + ध्वे » द्विड्ढ्वे (dviḍḍhve)</p></blockquote><p>4. -s + dh- » -dh- (Wegfall des -s)</p><blockquote><p>z.B. आस् 2Ā: आस् + ध्वे » आध्वे (ādhve)</p></blockquote><h3 id="_44-2-2-zum-wortsandhi-fur-s" tabindex="-1">44.2.2. Zum Wortsandhi für s- <a class="header-anchor" href="#_44-2-2-zum-wortsandhi-fur-s" aria-label="Permalink to &quot;44.2.2. Zum Wortsandhi für s-&quot;">​</a></h3><p>1. -s + s- » -ts- oder (nicht wahlweise!) -ss- (so in 2. Präsensklasse)</p><blockquote><p>Beispiele:</p><p>वस् 1P: Futur: वस् + स्य + ति » वत्स्यति (vatsyati)</p><p>वस् 2Ā: वस् + से » वस्से (vasse)</p></blockquote><p>2. -ṣ + s- » -kṣ-</p><blockquote><p>z.B. द्विष् 2U: द्वेष् + सि » द्वेक्षि (dvekṣi)</p></blockquote><h2 id="_44-3-bildung-der-verbalformen-der-2-person-मध्यमः-athematischer-stamme-ohne-vokalisch-endendem-suffix" tabindex="-1">44.3.  Bildung der Verbalformen der 2. Person (मध्यमः) athematischer Stämme ohne vokalisch endendem Suffix <a class="header-anchor" href="#_44-3-bildung-der-verbalformen-der-2-person-मध्यमः-athematischer-stamme-ohne-vokalisch-endendem-suffix" aria-label="Permalink to &quot;44.3.  Bildung der Verbalformen der 2. Person (मध्यमः) athematischer Stämme ohne vokalisch endendem Suffix&quot;">​</a></h2><h3 id="_44-3-1-zweite-prasensklasse-अदादि" tabindex="-1">44.3.1. Zweite Präsensklasse (अदादि) <a class="header-anchor" href="#_44-3-1-zweite-prasensklasse-अदादि" aria-label="Permalink to &quot;44.3.1. Zweite Präsensklasse (अदादि)&quot;">​</a></h3><p>द्विष् 2U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>द्वेक्षि</td><td>द्विष्ठ</td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अद्वेट्</td><td></td></tr><tr><td>a-dveṣ + s</td><td>अद्विष्ट</td><td>अद्विष्ठास्</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>द्विष्यास्</td><td>द्विष्यात</td></tr></tbody></table></blockquote><p>आस् 2Ā</p><blockquote><table tabindex="0"><thead><tr><th></th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td></tr><tr><td>लट्</td><td>आस्से</td></tr><tr><td>Imperfekt</td><td></td></tr><tr><td>लङ्</td><td>आस्थास्</td></tr><tr><td>Optativ</td><td></td></tr><tr><td>विधिलिङ्</td><td>आसीथास्</td></tr></tbody></table></blockquote><p>दुह् 2U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>धोक्षि</td><td>दुग्ध</td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अधोक्</td><td></td></tr><tr><td>aus: adhokṣ</td><td>अदुग्ध</td><td>अदुग्धास्</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>दुह्यास्</td><td>दुह्यात</td></tr></tbody></table></blockquote><p>इ 2P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>एषि</td><td>इथ</td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>ऐस्</td><td></td></tr><tr><td>a + e + s</td><td>ऐत</td><td></td></tr><tr><td>a + i + ta</td><td></td><td></td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>इयास्</td><td>इयात</td></tr><tr><td>iy-ī-thās</td><td>इयीध्वम्</td><td></td></tr></tbody></table></blockquote><p>हन् 2P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td></tr><tr><td>लट्</td><td>हंसि</td></tr><tr><td>han + si</td><td>हथ</td></tr><tr><td>aus: *hn + ta</td><td></td></tr><tr><td>Imperfekt</td><td></td></tr><tr><td>लङ्</td><td>अहन्</td></tr><tr><td>aus: a-han +s</td><td>अहत</td></tr><tr><td>aus: a-*hn + ta</td><td></td></tr><tr><td>Optativ</td><td></td></tr><tr><td>विधिलिङ्</td><td>हन्यास्</td></tr></tbody></table></blockquote><p>स्तु 2U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>स्तौषि</td><td></td></tr><tr><td>स्तवीषि</td><td>स्तुथ</td><td></td></tr><tr><td>स्तुवीथ</td><td>स्तुषे</td><td></td></tr><tr><td>स्तुवीषे</td><td>स्तुध्वे</td><td></td></tr><tr><td>स्तुवीध्वे</td><td></td><td></td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अस्तौस्</td><td></td></tr><tr><td>अस्तवीस्</td><td>स्तुत</td><td></td></tr><tr><td>अस्तुवीत</td><td>अस्तुथास्</td><td></td></tr><tr><td>अस्तुवीथास्</td><td>स्तुध्वम्</td><td></td></tr><tr><td>अस्तुवीध्वम्</td><td></td><td></td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>स्तुयास्</td><td></td></tr><tr><td>स्तुवीयास्</td><td>स्तुयात</td><td></td></tr><tr><td>स्तुवीयात</td><td>स्तुवीथास्</td><td></td></tr><tr><td>stu + ī-thās</td><td>स्तुवीध्वम्</td><td></td></tr></tbody></table></blockquote><p>अस् 2P (besonders zu merken!)</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td></tr><tr><td>लट्</td><td>असि</td></tr><tr><td>Imperfekt</td><td></td></tr><tr><td>लङ्</td><td>आसीस्</td></tr><tr><td>Optativ</td><td></td></tr><tr><td>विधिलिङ्</td><td>स्यास्</td></tr></tbody></table></blockquote><p>तत्त्वमसि</p><p>शास् 2P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td></tr><tr><td>लट्</td><td>शास्सि</td></tr><tr><td>Imperfekt</td><td></td></tr><tr><td>लङ्</td><td>अशास्</td></tr><tr><td>Optativ</td><td></td></tr><tr><td>विधिलिङ्</td><td>शिष्यास्</td></tr></tbody></table></blockquote><p>अद् 2P bildet die 2. und 3.sg.P.Imperfekt thematisch!</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td></tr><tr><td>लट्</td><td>अत्सि</td></tr><tr><td>Imperfekt</td><td></td></tr><tr><td>लङ्</td><td>2.sg. आदस्</td></tr><tr><td>3.sg. आदत्</td><td></td></tr></tbody></table><p>| अत्त | | Optativ<br> विधिलिङ् | अद्यास् | द्यात |</p></blockquote><h2 id="_44-4-der-vokativ-आमन्त्रितम्" tabindex="-1">44.4. Der Vokativ (आमन्त्रितम्) <a class="header-anchor" href="#_44-4-der-vokativ-आमन्त्रितम्" aria-label="Permalink to &quot;44.4. Der Vokativ (आमन्त्रितम्)&quot;">​</a></h2><p>Die einheimischen Grammatiker betrachten den Vokativ (आमन्त्रितम्) nicht als eigenen Kasus, sondern nur als Modifikation des Nominativ (प्रथमा).</p><p>Der Vokativ dient dem Anruf, dem Ansprechen und steht außerhalb des Zusammenhangs mit dem übrigen Satz, unterscheidet sich also von den anderen Kasus, die eine Beziehung zum Verb oder zu einem anderen Nomen ausdrücken.</p><p>Meist wird der Vokativ an den Beginn des Satzes gestellt:</p><blockquote><p>बाल किं वदसि = &quot;Kind, was sagst du?&quot;</p></blockquote><p><img src="'+e+'" alt=""></p><p>Man vermeide die Übersetzung des Vokativ mit &quot;O ...&quot;. Wir benutzen im Deutschen ständig Vokative, wenn wir z.B. sagen: &quot;Schatz, was kochen wir heute?&quot;. Niemand wird in dieser Bedeutung sagen: &quot;O Schatz, was kochen wir heute?&quot;</p><p><img src="'+e+'" alt=""></p><p><img src="'+n+'" alt=""><br> Abb.: Zur richtigen Verwendung von &quot;O&quot; im Deutschen: &quot;O Mann!&quot;<br>  Zeichnung von Henri Gerbault (1863 - 1930) (Public domain)</p><p>Die Formen des Vokativ Plural und Dual sind identisch mit denen des Nominativ (प्रथमा) Plural bzw. Dual.</p><p>Die Formen des Vokativ Singular folgen in <a href="./lektion45">Lektion 45</a>.</p><h2 id="_44-5-wortliste" tabindex="-1">44.5. Wortliste <a class="header-anchor" href="#_44-5-wortliste" aria-label="Permalink to &quot;44.5. Wortliste&quot;">​</a></h2><p>प्रति Präverb: zurück, wider, gegen - hin</p><blockquote><p>z.B.</p><p>हन्  + प्रति 2P प्रतिहन्ति : zurückschlagen</p><p>वद् + प्रति 1P प्रतिवदति : zurücksagen = antworten</p><p>ख्या + प्रति  + आ 2P प्रत्याख्याति : zurückweisen, verschmähen</p></blockquote><p>या 2P याति : gehen, fahren</p><blockquote><p>Perf. IV ययौ<br> Fut. यास्यति<br> Pass. यायते<br> Kaus. यापयति<br> PPP यात<br> Inf. यातुम्</p><p>davon:</p><p>यान n.: Gehen, Weg, Fahrzeug</p></blockquote><p><img src="'+o+'" alt=""><br> Abb.: रेल्यानम्<br> वाराणआस्याम्, १९७४<br> [Bildquelle: danielguip. -- <a href="http://www.flickr.com/photos/danielguip/118349247/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/danielguip/118349247/</a>. -- Zugriff am 2009-01-08. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>शी 2Ā शेते : liegen. Diese Wurzel hat in allen Formen des Präsensstamms Hochstufe: 1.sg.Ind.Präs.Ā शेये (śe + e). Folgende Formen sind besonders zu beachten: 3.pl.Ind.Präs.Ā  शेरते , 3.pl.Imperf.Ā अशेरत</p><blockquote><p>Perf. IIIa शिश्ये (śi-śī + e)<br> Fut. शयिष्यते<br> Kaus. शापयति<br> PPP शयित<br> Inf. शयितुम्</p><p>davon:</p><p>शयन n.: Liege, Bett</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: योगी शयने शेते<br> [Bildquelle: Gurumustuk Singh. -- <a href="http://www.flickr.com/photos/mrsikhnet/218757195/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mrsikhnet/218757195/</a>. -- Zugriff am 2009-01-08. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>नन्द् 1P नन्दति : sich freuen an (तृतीयया)</p><blockquote><p>Perf. I ननन्द<br> Fut. नन्दिष्यति<br> Pass.: नन्द्यते<br> Kaus. नन्दयति<br> PPP नन्दित<br> Inf. नन्दितुम्<br> Absol. -नन्द्य<br> Gerundiv नन्द्य</p><p>davon:</p><p>नन्दिन् 3: durch (besondere) Freude gekennzeichnet, freudig ; m. Name des Reittiers (वहन) des शिव (ein Stier)</p></blockquote><p><img src="'+h+'" alt=""><br> Abb.: नन्दी<br> Kodagu = ಕೊಡಗು<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/377335641/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/377335641/</a>. -- Zugriff am 2009-01-08. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>नन्द् + अभि 1P (1Ā)  अभिनन्दति : seine Freude haben an (द्वितीयया), jemanden freudig begrüßen, willkommen heißen</p><p>यम् 1P यच्छति : halten, tragen ; darreichen, gewähren ; zusammenhalten, bändigen, zügeln, bezwingen</p><blockquote><p>Perf. Vb ययाम, येमुर्<br> Fut. यंस्यति<br> Pass. यम्यते<br> Kaus. यामयति aber: नियमयति<br> PPP यत<br> Inf. यन्तुम्<br> Absol. -यम्य</p></blockquote><p>यम् + आ 1U आयच्छति : dehnen, ausstrecken</p><blockquote><p>PPP आयत 3: lang gestreckt</p></blockquote><p><img src="'+u+'" alt=""><br> Abb.: आयतो मरुः (मरु m. = &quot;Wüste&quot;)<br> थार मरुस्थल<br> [Bildquelle: Amre Ghiba. -- <a href="http://www.flickr.com/photos/amre/1476216243/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/amre/1476216243/</a>. -- Zugriff am 2009-01-08. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>यम् + प्र 1P प्रयच्छति : darreichen, anbieten, übergeben</p><p>यम् + सम् 1P संयच्छति : zusammenbinden, anbinden, bändigen</p><p>यत् 1Ā यतते : streben nach (सप्तमी, चतुर्थी, द्वितीया)</p><blockquote><p>Perf. Vb येते<br> Fut. यतिष्यते<br> Pass. यत्यते<br> Kaus. यातयति<br> PPP यत्त<br> Inf.यतितुम्</p><p>davon:</p><p>यत्न m.: Bemühung, Anstrengung</p></blockquote><p><img src="'+b+'" alt=""><br> Abb.: यत्नेन<br> Kollam = കൊല്ലം<br> [Bildquelle: MalayalaM. -- <a href="http://www.flickr.com/photos/malayalam/35026906/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/malayalam/35026906/</a>. -- Zugriff am 2009-01-08. --  <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>रभ् 1Ā रभते (Nebenform zu लभ्): fassen</p><blockquote><p>Perf. Vb रेभे<br> Fut. रप्स्यते<br> Pass. रभ्यते<br> Kaus. रम्भयति<br> PPP रब्ध<br> Inf. रब्धुम्<br> Absol. -रभ्य</p></blockquote><p>रभ् + आ 1Ā आरभते : anfassen, beginnen, unternehmen</p><p>प्रव्रज्या f. (zu प्र-व्रज्): das Fortgehen aus dem Heim in die Heimlosigkeit ; Zeremonie, mit der man buddhistischer Novize wird (Pali: पब्बजा)</p><blockquote><p>Siehe:</p><blockquote><p><strong>Payer, Alois &lt;1944 - &gt;:</strong> Vinayamukha : Grundbegriffe der Ordensregeln und des Ordensrechts des Theravāda. -- Teil I. -- (Materialien zu den Grundbegriffen des Buddhismus). -- <em>URL</em>: <a href="http://www.payer.de/buddhgrund/vinaya01.htm" target="_blank" rel="noreferrer">http://www.payer.de/buddhgrund/vinaya01.htm</a></p></blockquote><p><img src="'+p+'" alt=""><br> Abb.: प्रव्रअज्या / पब्बजा<br> Thailand = ประเทศไทย<br> [Bildquelle: Midpath. -- <a href="http://www.flickr.com/photos/midpath/342678518/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/midpath/342678518/</a>. -- Zugriff am 2009-01-08. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p></blockquote><h2 id="_44-6-ubung" tabindex="-1">44.6. Übung <a class="header-anchor" href="#_44-6-ubung" aria-label="Permalink to &quot;44.6. Übung&quot;">​</a></h2><p>A) Bestimmen und übersetzen Sie folgende Formen:</p><ol><li>आदेः</li><li>आदः</li><li>अपुनाः</li><li>पुनः</li><li>आसीः</li><li>आसि</li><li>तन्वीथाः</li><li>अध्यैथाः</li><li>वित्थ</li><li>वीतम्</li><li>आध्वम्</li><li>पाथ</li><li>कथम्</li><li>स्वपिषि</li><li>अश्नीयात</li><li>आश्नाः</li><li>आश्नुवत</li><li>यन्ति</li><li>याथ</li><li>यथा</li><li>इयात</li><li>शिष्ठ</li><li>शिष्टः</li><li>आध्वे</li><li>अवक्</li><li>स्थ</li><li>तस्थौ</li><li>बध्नीथ</li><li>अशिष्ट</li><li>धुक्षे</li><li>धोक्ष्ये</li><li>वध्वे</li><li>अहन्</li><li>आख्येयम्</li><li>वदेयम्</li><li>यामः</li><li>येमिम</li><li>शेरते</li><li>द्विषीथाः</li><li>कुरुथ</li><li>आप्नुत</li><li>विक्रीणीध्वम्</li><li>सुन्मः</li><li>रोदिषि</li><li>अस्तवीः</li><li>अशृणुत</li><li>ब्रुवीध्वम्</li><li>द्विड्ढ्वे</li><li>शेकुः</li><li>चिनुथ</li><li>हथ</li><li>हतः</li></ol><p><img src="'+m+'" alt=""><br> Abb.: कस्माद्रोदिषि<br> [Bildquelle: bartpogoda. -- <a href="http://www.flickr.com/photos/bartpogoda/2068996900/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/bartpogoda/2068996900/</a>. -- Zugriff am 2009-01-08. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>B) Übersetzen Sie:</p><p>अक्रोधेन जयेत्क्रोधमसाधुं सधुना जयेज्जयेत्सत्येन चानृतम् ॥१॥</p><p>पुत्राः किं पितृभ्यः पिण्डान्प्रायच्छत ॥२॥</p><p>कानि शास्त्राणि काश्यामध्यैथाः ॥३॥</p><p>बुद्धपुत्राश्चेन्महाशयनेषु शयीरन्प्रव्रज्यायां कृतं व्रतं न चरेयुः ॥४॥</p><p>अप्यार्ययुद्धाख्यानमाख्यास्यन्तं गुरुमभ्यनन्दः ॥५॥</p><p>द्वेष्यमपि न द्विष्यात लोभनीयं च न लुभ्येतैवं च प्रसन्ना भविष्यथ ॥६॥</p><p>न योत्स्य इत्यर्जुन उवाच ॥७॥</p><p>अशोच्यानशोचः प्रज्ञावादांश्च प्रवक्तुमैच्छः ।<br> मृताञ्जीवतश्च बुद्धिमन्तो न शोचन्ति ॥८॥</p><h2 id="_44-7-wiederholungsubung-zur-formenlehre" tabindex="-1">44.7. Wiederholungsübung zur Formenlehre <a class="header-anchor" href="#_44-7-wiederholungsubung-zur-formenlehre" aria-label="Permalink to &quot;44.7. Wiederholungsübung zur Formenlehre&quot;">​</a></h2><p>Bestimmen Sie folgende Formen:</p><ol><li>वदिता</li><li>उदिता</li><li>धातुः</li><li>दधुः</li><li>अदधुः</li><li>दध्युः</li><li>रक्षामि</li><li>रक्षाणि</li><li>रक्षीणि</li><li>रक्षिणी</li><li>राजनि</li><li>आसि</li><li>इज्ये</li><li>अयुध्ये</li><li>अयोध्ये</li><li>अयोधये</li><li>शोचनीयायाम्</li><li>वर्त्स्यति</li><li>आसन्</li><li>असन्</li><li>बिभ्यति</li><li>कुत्र</li><li>चेरिम</li><li>योक्ष्ये</li><li>योज्ये</li><li>युज्ये</li><li>चिक्ये</li><li>अजायामहि</li><li>स्मर्येय</li><li>स्मर्याय</li><li>कया</li><li>क्रेया</li><li>आत्मने</li><li>अदानम्</li><li>आददानम्</li><li>सेदिम</li><li>क्व</li><li>पिपूर्मः</li><li>कैः</li><li>कृत्येन</li></ol>',111)])])}const I=r(c,[["render",k]]);export{_ as __pageData,I as default};
